sql:
SELECT item_id, SUM(item_outlet_sales) AS total_sales
FROM sales_data
GROUP BY item_id;

SELECT item_name, SUM(item_stock_quantity) AS total_stock
FROM items
GROUP BY item_name;

external_knowledge:
- 'Popular Tier 1 outlets' refers to outlets located in Tier 1 regions; 
- 'More dealings than usual' indicates a condition where the number of sales exceeds 50 items;
- 'Average sales and total transaction counts' are derived from the sale totals and the count of item IDs respectively.

sql:
SELECT SUM(sale_total) AS total_amount_spent
FROM sales_data
WHERE customer_id = 1;

SELECT SUM(item_outlet_sales) AS total_sales_amount
FROM sales_data
WHERE item_id = (SELECT item_id FROM items WHERE item_identifier = 'FDA15');
